// Builtin declarations
void *__builtin_riscv_esp_fft_bitrev_m(void *Rs1, void *qv_out, unsigned int fft_bit_width);
void *__builtin_riscv_esp_vst_128_ip_m(esp_vec128_t Data, void *Ptr, int Imm);

// Test MOVX.W.FFT.BIT.WIDTH and MOVX.R.FFT.BIT.WIDTH with explicit state passing
// CHECK-LABEL: define dso_local i32 @test_movx_fft_bit_width_write_read(
// CHECK-SAME: i32 noundef [[RS1_VAL:%.*]]) local_unnamed_addr #[[ATTR0:[0-9]+]] {
// CHECK-NEXT:  [[ENTRY:.*:]]
// CHECK-NEXT:    [[TMP0:%.*]] = tail call i32 @llvm.riscv.esp.movx.w.fft.bit.width.m(i32 [[RS1_VAL]])
// CHECK-NEXT:    [[TMP1:%.*]] = tail call i32 @llvm.riscv.esp.movx.r.fft.bit.width.m(i32 [[TMP0]])
// CHECK-NEXT:    ret i32 [[TMP1]]
//
unsigned int test_movx_fft_bit_width_write_read(unsigned int rs1_val) {
    // Write to FFT_BIT_WIDTH: FFT_BIT_WIDTH[3:0] = Rs1[3:0] (hardware automatically uses only low 4 bits)
    // FFT_BIT_WIDTH stores unsigned bit width mode (0-15)
    unsigned int fft_bit_width = __builtin_riscv_esp_movx_w_fft_bit_width_m(rs1_val);
    // Read from FFT_BIT_WIDTH: rd[31:0] = {28'b0, FFT_BIT_WIDTH[3:0]} (hardware automatically extracts only low 4 bits from 32-bit FFT_BIT_WIDTH)
    return __builtin_riscv_esp_movx_r_fft_bit_width_m(fft_bit_width);
}

// Test ESP.BITREV with FFT_BIT_WIDTH setup using MOVX instructions
// This test demonstrates:
// 1. Setting FFT_BIT_WIDTH using MOVX.W
// 2. Executing BITREV (which uses FFT_BIT_WIDTH implicitly)
// 3. Storing the Result using VST
// 4. Reading FFT_BIT_WIDTH back using MOVX.R for verification
// CHECK-LABEL: define dso_local ptr @test_bitrev_with_fft_bit_width(
// CHECK-SAME: ptr noundef [[RS1:%.*]], ptr noundef [[DST:%.*]], i32 noundef [[BIT_WIDTH:%.*]]) local_unnamed_addr #[[ATTR2:[0-9]+]] {
// CHECK-NEXT:  [[ENTRY:.*:]]
// CHECK-NEXT:    [[TMP0:%.*]] = tail call i32 @llvm.riscv.esp.movx.w.fft.bit.width.m(i32 [[BIT_WIDTH]])
// CHECK-NEXT:    [[TMP1:%.*]] = tail call { ptr, <8 x i16> } @llvm.riscv.esp.fft.bitrev.m(ptr [[RS1]], i32 [[TMP0]])
// CHECK-NEXT:    [[TMP2:%.*]] = extractvalue { ptr, <8 x i16> } [[TMP1]], 1
// CHECK-NEXT:    [[TMP3:%.*]] = bitcast <8 x i16> [[TMP2]] to <16 x i8>
// CHECK-NEXT:    [[TMP4:%.*]] = tail call ptr @llvm.riscv.esp.vst.128.ip.m(<16 x i8> [[TMP3]], ptr [[DST]], i32 16)
// CHECK-NEXT:    [[TMP5:%.*]] = tail call i32 @llvm.riscv.esp.movx.r.fft.bit.width.m(i32 [[TMP0]])
// CHECK-NEXT:    ret ptr [[TMP4]]
//
void *test_bitrev_with_fft_bit_width(void *Rs1, void *dst, unsigned int bit_width) {
    // Step 1: Set FFT_BIT_WIDTH using MOVX.W
    // FFT_BIT_WIDTH[3:0] = bit_width[3:0] (hardware automatically uses only low 4 bits)
    unsigned int fft_bit_width = __builtin_riscv_esp_movx_w_fft_bit_width_m(bit_width);

    // Step 2: Execute BITREV - uses FFT_BIT_WIDTH explicitly
    // BITREV performs bit reversal based on FFT_BIT_WIDTH value (3-10)
    // Returns: updated pointer (Rs1 + 8) and Qv (v8i16 vector)
    // Note: FFT_BIT_WIDTH is passed explicitly for explicit state passing
    esp_vec128_16_t Qv;
    void *new_ptr = __builtin_riscv_esp_fft_bitrev_m(Rs1, &Qv, fft_bit_width);

    // Step 3: Store the Result using VST.128.IP
    // Convert v8i16 to v16i8 (same memory layout, different view)
    esp_vec128_t qv_v8 = *(esp_vec128_t *)&Qv;
    void *final_ptr = __builtin_riscv_esp_vst_128_ip_m(qv_v8, dst, 16);

    // Step 4: Read FFT_BIT_WIDTH back for verification
    unsigned int read_back = __builtin_riscv_esp_movx_r_fft_bit_width_m(fft_bit_width);
    (void)read_back; // Suppress unused variable warning

    return final_ptr;
}

